-- =====================================================================
-- V7 — Customer data from Drivers Student Manager.xlsx
-- =====================================================================
--  Seeds:
--    * 1 school  (SRoadTutor Driving School)
--    * 2 driver users + instructor records + driver payment settings
--   * 11 student users + student records
--    * 14 scheduled sessions  + 6 synthetic test sessions
--    * 12 payment records
--    * 25 individual mistake logs (session_mistakes)
--
--  Login: every seeded user has password 'Password1' (BCrypt strength 12).
--  Emails are synthesised because the source sheet has phone-only data.
--
--  Gated by Flyway placeholder `${seed-customer}` (mirrors the
--  `${seed-dev}` pattern used by V4). Only `application-dev.yml` sets it
--  to "true"; every other profile (qa / prod / test, plus the base
--  default in application.yml) keeps it "false". The Flyway version
--  history still advances either way — that means switching the gate
--  off later cannot accidentally re-trigger insertion.
--
--  Idempotent via "skip if school already exists" — keeps the gate
--  belt-and-suspenders against manual re-runs in dev.
-- =====================================================================

DO $body$
BEGIN
    IF '${seed-customer}' <> 'true' THEN
        RAISE NOTICE 'V7 customer seed disabled (seed-customer=${seed-customer}) — skipping.';
        RETURN;
    END IF;

    IF EXISTS (SELECT 1 FROM schools WHERE id = 'c3d9a79c-3ad8-5e22-8462-124ed13c5382'::uuid) THEN
        RAISE NOTICE 'V7 customer data already loaded — skipping.';
        RETURN;
    END IF;

    -- ---------------- school ----------------
    VALUES ('c3d9a79c-3ad8-5e22-8462-124ed13c5382'::uuid, 'SRoadTutor Driving School', NULL, 'FREE', 'SK', 'SGI', NOW(), NOW());

    -- ---------------- driver users (role=INSTRUCTOR, owner=first) ----------------

    UPDATE schools SET owner_id = 'ef94ca87-3326-5634-99aa-3d1d1d848f17'::uuid WHERE id = 'c3d9a79c-3ad8-5e22-8462-124ed13c5382'::uuid;

    -- ---------------- instructors (1:1 with driver users) ----------------

    -- ---------------- driver_payment_settings ----------------

    -- ---------------- student users + student records ----------------

    -- ---------------- scheduled lesson sessions ----------------

    -- ---------------- synthetic sessions for orphan test results ----------------

    -- ---------------- payments (per session) ----------------

    -- ---------------- session_mistakes from Test_Results ----------------
    -- Keyed by mistake_categories.source_code ('M001'..'M056') seeded in V6.

    RAISE NOTICE 'V7 customer data loaded successfully.';
END
$body$ LANGUAGE plpgsql;

